/**
 * Unit tests: settingsParser env extraction
 *
 * Tests extractTopLevelEnvVars behavior through parseSettings driving port.
 * Properties: non-string filtering, alphabetical sorting, scope attribution.
 * Examples: edge cases, empty/missing blocks.
 */

import { describe, it, expect } from "vitest";
import fc from "fast-check";
import { parseSettings } from "../../../../../src/plugins/norbert-config/domain/settingsParser";
import type { EnvVarEntry } from "../../../../../src/plugins/norbert-config/domain/types";

// ---------------------------------------------------------------------------
// Property: non-string values are always filtered out
// ---------------------------------------------------------------------------

describe("extractTopLevelEnvVars via parseSettings", () => {
  it("filters out all non-string values", () => {
    const mixedEnv = fc.record({
      stringVal: fc.constant("hello"),
      numberVal: fc.constant(42),
      objectVal: fc.constant({ nested: true }),
      arrayVal: fc.constant([1, 2]),
      nullVal: fc.constant(null),
      boolVal: fc.constant(true),
    });

    fc.assert(
      fc.property(mixedEnv, (envBlock) => {
        const json = JSON.stringify({ env: envBlock });
        const result = parseSettings(json, "user");
        if (result.tag !== "parsed") return;

        // Only stringVal should survive
        expect(result.envVars).toHaveLength(1);
        expect(result.envVars[0].key).toBe("stringVal");
        expect(result.envVars[0].value).toBe("hello");
      }),
      { numRuns: 10 },
    );
  });

  // ---------------------------------------------------------------------------
  // Property: results are always sorted by key
  // ---------------------------------------------------------------------------

  it("results are always sorted alphabetically by key", () => {
    const envArb = fc.dictionary(
      fc.stringMatching(/^[A-Z][A-Z0-9_]{0,15}$/),
      fc.string({ maxLength: 30 }),
      { minKeys: 2, maxKeys: 10 },
    );

    fc.assert(
      fc.property(envArb, (envBlock) => {
        const json = JSON.stringify({ env: envBlock });
        const result = parseSettings(json, "user");
        if (result.tag !== "parsed") return;

        const keys = result.envVars.map((e) => e.key);
        const sorted = [...keys].sort((a, b) => a.localeCompare(b));
        expect(keys).toEqual(sorted);
      }),
      { numRuns: 100 },
    );
  });

  // ---------------------------------------------------------------------------
  // Property: scope is always propagated from caller
  // ---------------------------------------------------------------------------

  it("scope matches the scope parameter passed to parseSettings", () => {
    const scopeArb = fc.constantFrom("user" as const, "project" as const);

    fc.assert(
      fc.property(scopeArb, (scope) => {
        const json = JSON.stringify({ env: { KEY: "val" } });
        const result = parseSettings(json, scope);
        if (result.tag !== "parsed") return;

        expect(result.envVars.every((e) => e.scope === scope)).toBe(true);
      }),
    );
  });

  // ---------------------------------------------------------------------------
  // Example: source field is "settings.json"
  // ---------------------------------------------------------------------------

  it("sets source to settings.json for each entry", () => {
    const json = JSON.stringify({ env: { MY_VAR: "val" } });
    const result = parseSettings(json, "user");

    expect(result.tag).toBe("parsed");
    if (result.tag !== "parsed") return;

    expect(result.envVars[0].source).toBe("settings.json");
  });

  // ---------------------------------------------------------------------------
  // Example: filePath defaults to empty string
  // ---------------------------------------------------------------------------

  it("sets filePath to empty string (populated by caller)", () => {
    const json = JSON.stringify({ env: { MY_VAR: "val" } });
    const result = parseSettings(json, "user");

    expect(result.tag).toBe("parsed");
    if (result.tag !== "parsed") return;

    expect(result.envVars[0].filePath).toBe("");
  });

  // ---------------------------------------------------------------------------
  // Example: env block is not an object (array, string, number)
  // ---------------------------------------------------------------------------

  it("returns empty array when env block is an array", () => {
    const json = JSON.stringify({ env: ["not", "an", "object"] });
    const result = parseSettings(json, "user");

    expect(result.tag).toBe("parsed");
    if (result.tag !== "parsed") return;

    expect(result.envVars).toEqual([]);
  });

  it("returns empty array when env block is a string", () => {
    const json = JSON.stringify({ env: "not an object" });
    const result = parseSettings(json, "user");

    expect(result.tag).toBe("parsed");
    if (result.tag !== "parsed") return;

    expect(result.envVars).toEqual([]);
  });
});

/**
 * Unit tests: MCP file aggregation and source attribution
 *
 * Tests for aggregateMcpFiles() and source attribution on McpServerConfig.
 * Property-based tests validate structural invariants:
 *   - Source attribution is always present on every MCP server
 *   - Server count equals sum of servers across all mcp files
 *   - Malformed/empty mcp files produce zero servers, no crash
 *   - Servers from mcpFiles merge with settings.json servers
 */

import { describe, it, expect } from "vitest";
import fc from "fast-check";
import {
  aggregateConfig,
  aggregateMcpFiles,
  type RawClaudeConfig,
  type FileEntry,
} from "../../../../../src/plugins/norbert-config/domain/configAggregator";

// ---------------------------------------------------------------------------
// Generators
// ---------------------------------------------------------------------------

const scopeArb = fc.constantFrom("user" as const, "project" as const, "plugin" as const);

const sourceArb = fc.constantFrom(".claude.json", ".mcp.json", "discord", "slack");

/** Server name arbitrary using constantFrom for speed */
const serverNameArb = fc.constantFrom(
  "memory-server", "git-server", "db-server", "api-server", "slack-bot",
  "discord-bot", "fs-server", "search-srv", "cache-srv", "log-srv",
);

/** Generate a valid mcpServers JSON block with 1-3 servers */
const mcpServersJsonArb = fc
  .array(
    fc.tuple(
      serverNameArb,
      fc.constantFrom("stdio", "sse", "streamable-http"),
      fc.constantFrom("npx srv", "node index.js", "python main.py"),
    ),
    { minLength: 1, maxLength: 3 },
  )
  .map((servers) => {
    const obj: Record<string, unknown> = {};
    for (const [name, type, command] of servers) {
      obj[name] = { type, command, args: [] };
    }
    return JSON.stringify({ mcpServers: obj });
  });

/** Generate a FileEntry containing valid MCP server JSON */
const mcpFileEntryArb: fc.Arbitrary<FileEntry> = fc
  .tuple(mcpServersJsonArb, scopeArb, sourceArb)
  .map(([content, scope, source]) => ({
    path: `${scope === "user" ? "~/.claude" : "./.claude"}/${source}`,
    content,
    scope,
    source,
  }));

/** Generate a FileEntry with malformed JSON */
const malformedMcpFileEntryArb: fc.Arbitrary<FileEntry> = fc
  .tuple(
    fc.constantFrom("{ broken", "not json", "{,}", "[]", "null", "42"),
    scopeArb,
    sourceArb,
  )
  .map(([content, scope, source]) => ({
    path: `./.claude/${source}`,
    content,
    scope,
    source,
  }));

/** Generate a FileEntry with valid JSON but no mcpServers key */
const noMcpServersFileEntryArb: fc.Arbitrary<FileEntry> = fc
  .tuple(scopeArb, sourceArb)
  .map(([scope, source]) => ({
    path: `./.claude/${source}`,
    content: JSON.stringify({ permissions: { allow: [] } }),
    scope,
    source,
  }));

// ---------------------------------------------------------------------------
// Helper: count servers in a valid mcp file entry
// ---------------------------------------------------------------------------

function countServersInEntry(entry: FileEntry): number {
  try {
    const parsed = JSON.parse(entry.content);
    const servers = parsed.mcpServers;
    if (typeof servers === "object" && servers !== null && !Array.isArray(servers)) {
      return Object.keys(servers).length;
    }
    return 0;
  } catch {
    return 0;
  }
}

// ---------------------------------------------------------------------------
// Properties: aggregateMcpFiles
// ---------------------------------------------------------------------------

describe("aggregateMcpFiles properties", () => {
  it("server count equals sum of servers across all mcp file entries", () => {
    fc.assert(
      fc.property(
        fc.array(mcpFileEntryArb, { minLength: 0, maxLength: 3 }),
        (mcpFiles) => {
          const result = aggregateMcpFiles(mcpFiles);
          const expectedCount = mcpFiles.reduce(
            (sum, entry) => sum + countServersInEntry(entry),
            0,
          );
          expect(result).toHaveLength(expectedCount);
        },
      ),
      { numRuns: 30 },
    );
  });

  it("every server has non-empty source, scope, and filePath from its FileEntry", () => {
    fc.assert(
      fc.property(
        fc.array(mcpFileEntryArb, { minLength: 1, maxLength: 3 }),
        (mcpFiles) => {
          const result = aggregateMcpFiles(mcpFiles);
          for (const server of result) {
            expect(server.source).toBeTruthy();
            expect(server.scope).toBeTruthy();
            expect(server.filePath).toBeTruthy();
          }
        },
      ),
      { numRuns: 30 },
    );
  });

  it("source and scope on each server match the originating FileEntry", () => {
    fc.assert(
      fc.property(mcpFileEntryArb, (entry) => {
