/**
 * Acceptance tests: Env Var Extraction (config-env-viewer, step 01-01)
 *
 * Validates that settings.json top-level env block is parsed into
 * EnvVarEntry[] with scope/source/filePath attribution, sorted
 * alphabetically by key. Non-string values are filtered out.
 *
 * Driving port: pure domain function (parseSettings)
 */

import { describe, it, expect } from "vitest";
import fc from "fast-check";
import { parseSettings } from "../../../src/plugins/norbert-config/domain/settingsParser";

// ---------------------------------------------------------------------------
// WALKING SKELETON
// ---------------------------------------------------------------------------

describe("User views environment variables from settings", () => {
  it("parses settings with 5 OTEL env vars into 5 sorted entries", () => {
    // Given settings.json with 5 OTEL env vars in top-level env block
    const settingsJson = JSON.stringify({
      env: {
        OTEL_EXPORTER_OTLP_ENDPOINT: "http://localhost:4318",
        OTEL_EXPORTER_OTLP_PROTOCOL: "http/protobuf",
        OTEL_LOG_LEVEL: "debug",
        OTEL_SERVICE_NAME: "norbert",
        OTEL_TRACES_SAMPLER: "always_on",
      },
    });

    // When settings are parsed at user scope
    const result = parseSettings(settingsJson, "user");

    // Then parsing succeeds
    expect(result.tag).toBe("parsed");
    if (result.tag !== "parsed") return;

    // And 5 env var entries are extracted
    expect(result.envVars).toHaveLength(5);

    // And entries are sorted alphabetically by key
    const keys = result.envVars.map((e) => e.key);
    expect(keys).toEqual([
      "OTEL_EXPORTER_OTLP_ENDPOINT",
      "OTEL_EXPORTER_OTLP_PROTOCOL",
      "OTEL_LOG_LEVEL",
      "OTEL_SERVICE_NAME",
      "OTEL_TRACES_SAMPLER",
    ]);

    // And each entry has correct scope
    expect(result.envVars.every((e) => e.scope === "user")).toBe(true);
  });

  // ---------------------------------------------------------------------------
  // SCOPE ATTRIBUTION
  // ---------------------------------------------------------------------------

  it("attributes user scope for user-level settings", () => {
    const settingsJson = JSON.stringify({
      env: { MY_VAR: "val" },
    });

    const result = parseSettings(settingsJson, "user");
    expect(result.tag).toBe("parsed");
    if (result.tag !== "parsed") return;

    expect(result.envVars[0].scope).toBe("user");
  });

  it("attributes project scope for project-level settings", () => {
    const settingsJson = JSON.stringify({
      env: { MY_VAR: "val" },
    });

    const result = parseSettings(settingsJson, "project");
    expect(result.tag).toBe("parsed");
    if (result.tag !== "parsed") return;

    expect(result.envVars[0].scope).toBe("project");
  });

  // ---------------------------------------------------------------------------
  // MISSING / EMPTY ENV BLOCK
  // ---------------------------------------------------------------------------

  it("produces empty array when env block is missing", () => {
    const settingsJson = JSON.stringify({ hooks: {} });

    const result = parseSettings(settingsJson, "user");
    expect(result.tag).toBe("parsed");
    if (result.tag !== "parsed") return;

    expect(result.envVars).toEqual([]);
  });

  it("produces empty array when env block is empty object", () => {
    const settingsJson = JSON.stringify({ env: {} });

    const result = parseSettings(settingsJson, "user");
    expect(result.tag).toBe("parsed");
    if (result.tag !== "parsed") return;

    expect(result.envVars).toEqual([]);
  });

  // ---------------------------------------------------------------------------
  // NON-STRING FILTERING
  // ---------------------------------------------------------------------------

  it("filters out non-string values (objects, numbers, arrays)", () => {
    const settingsJson = JSON.stringify({
      env: {
        GOOD_VAR: "hello",
        BAD_OBJECT: { nested: true },
        BAD_NUMBER: 42,
        BAD_ARRAY: [1, 2, 3],
        ALSO_GOOD: "world",
      },
    });

    const result = parseSettings(settingsJson, "user");
    expect(result.tag).toBe("parsed");
    if (result.tag !== "parsed") return;

    // Only string values kept, sorted alphabetically
    expect(result.envVars).toHaveLength(2);
    expect(result.envVars.map((e) => e.key)).toEqual(["ALSO_GOOD", "GOOD_VAR"]);
  });

  // ---------------------------------------------------------------------------
  // EDGE CASES
  // ---------------------------------------------------------------------------

  it("handles single env var", () => {
    const settingsJson = JSON.stringify({
      env: { SINGLE: "value" },
    });

    const result = parseSettings(settingsJson, "user");
    expect(result.tag).toBe("parsed");
    if (result.tag !== "parsed") return;

    expect(result.envVars).toHaveLength(1);
    expect(result.envVars[0].key).toBe("SINGLE");
    expect(result.envVars[0].value).toBe("value");
  });

  it("preserves special characters in values", () => {
    const settingsJson = JSON.stringify({
      env: { URL: "http://localhost:4318/v1/traces?key=abc&flag=true" },
    });

    const result = parseSettings(settingsJson, "user");
    expect(result.tag).toBe("parsed");
    if (result.tag !== "parsed") return;

    expect(result.envVars[0].value).toBe(
      "http://localhost:4318/v1/traces?key=abc&flag=true",
    );
  });

  it("includes empty string values", () => {
    const settingsJson = JSON.stringify({
      env: { EMPTY: "" },
    });

    const result = parseSettings(settingsJson, "user");
    expect(result.tag).toBe("parsed");
    if (result.tag !== "parsed") return;

    expect(result.envVars).toHaveLength(1);
    expect(result.envVars[0].value).toBe("");
  });

  // ---------------------------------------------------------------------------
  // MIXED VARS (6 including CUSTOM_LOG_LEVEL)
  // ---------------------------------------------------------------------------

  it("parses mixed env vars sorted correctly", () => {
    const settingsJson = JSON.stringify({
      env: {
        OTEL_EXPORTER_OTLP_ENDPOINT: "http://localhost:4318",
        OTEL_SERVICE_NAME: "norbert",
        CUSTOM_LOG_LEVEL: "info",
        OTEL_LOG_LEVEL: "debug",
        OTEL_EXPORTER_OTLP_PROTOCOL: "http/protobuf",
        OTEL_TRACES_SAMPLER: "always_on",
      },
    });

    const result = parseSettings(settingsJson, "user");
    expect(result.tag).toBe("parsed");
    if (result.tag !== "parsed") return;

    expect(result.envVars).toHaveLength(6);
    expect(result.envVars.map((e) => e.key)).toEqual([
      "CUSTOM_LOG_LEVEL",
      "OTEL_EXPORTER_OTLP_ENDPOINT",
      "OTEL_EXPORTER_OTLP_PROTOCOL",
      "OTEL_LOG_LEVEL",
      "OTEL_SERVICE_NAME",
      "OTEL_TRACES_SAMPLER",
    ]);
  });

  // ---------------------------------------------------------------------------
  // PROPERTY: always sorted, count matches
  // ---------------------------------------------------------------------------

  it("env vars are always sorted alphabetically and count matches entries", () => {
    const envArbitrary = fc.dictionary(
      fc.string({ minLength: 1, maxLength: 20 }).filter((s) => !s.includes('"')),
      fc.string({ maxLength: 50 }),
      { minKeys: 0, maxKeys: 20 },
    );

    fc.assert(
      fc.property(envArbitrary, (envBlock) => {
        const settingsJson = JSON.stringify({ env: envBlock });
        const result = parseSettings(settingsJson, "user");
        expect(result.tag).toBe("parsed");
        if (result.tag !== "parsed") return;

        // Count matches number of string entries
        const expectedCount = Object.values(envBlock).filter(
          (v) => typeof v === "string",
        ).length;
        expect(result.envVars).toHaveLength(expectedCount);

        // Always sorted alphabetically by key
        const keys = result.envVars.map((e) => e.key);
        const sortedKeys = [...keys].sort((a, b) => a.localeCompare(b));
        expect(keys).toEqual(sortedKeys);
      }),
      { numRuns: 100 },
    );
  });
});

tests/acceptance/config-env-viewer/env-a.source:
/**
 * Acceptance tests: Env Var Aggregation (config-env-viewer, step 01-02)
 *
 * Validates that env vars from settings parse result are threaded through
 * configAggregator into AggregatedConfig with filePath annotation from
 * the FileEntry path.
 *
 * Driving port: pure domain function (aggregateConfig)
 */

import { describe, it, expect } from "vitest";
import {
  aggregateConfig,
  type RawClaudeConfig,
  type FileEntry,
} from "../../../src/plugins/norbert-config/domain/configAggregator";

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

const fileEntry = (path: string, content: string, scope: "user" | "project"): FileEntry => ({
  path,
  content,
  scope,
  source: scope,
});

const emptyConfig = (scope: "user" | "project" | "both"): RawClaudeConfig => ({
  agents: [],
  commands: [],
  skills: [],
  settings: null,
  hooks: [],
  rules: [],
  claudeMdFiles: [],
  installedPlugins: null,
  pluginDetails: [],
  errors: [],
  scope,
});

// ---------------------------------------------------------------------------
// ACCEPTANCE SCENARIOS
// ---------------------------------------------------------------------------

describe("Env vars from settings are aggregated with filePath annotation", () => {
  it("aggregates 5 OTEL env vars from settings with filePath annotation", () => {
    // Given settings.json with 5 OTEL env vars
    const settingsJson = JSON.stringify({
      env: {
        OTEL_EXPORTER_OTLP_ENDPOINT: "http://localhost:4318",
        OTEL_EXPORTER_OTLP_PROTOCOL: "http/protobuf",
        OTEL_LOG_LEVEL: "debug",
        OTEL_SERVICE_NAME: "norbert",
        OTEL_TRACES_SAMPLER: "always_on",
      },
    });

    const rawConfig: RawClaudeConfig = {
      ...emptyConfig("user"),
      settings: fileEntry("~/.claude/settings.json", settingsJson, "user"),
    };

    // When the raw config is aggregated
    const aggregated = aggregateConfig(rawConfig);

    // Then aggregated config contains 5 env var entries
    expect(aggregated.envVars).toHaveLength(5);

    // And each entry has filePath annotated from the FileEntry path
    for (const entry of aggregated.envVars) {
      expect(entry.filePath).toBe("~/.claude/settings.json");
    }

    // And entries carry correct scope
    for (const entry of aggregated.envVars) {
      expect(entry.scope).toBe("user");
    }
  });

  it("produces empty envVars when settings is null", () => {
    // Given no settings file
    const rawConfig: RawClaudeConfig = emptyConfig("user");

    // When the raw config is aggregated
    const aggregated = aggregateConfig(rawConfig);

    // Then envVars is empty
    expect(aggregated.envVars).toEqual([]);
  });

  it("produces empty envVars when settings JSON is malformed", () => {
    // Given malformed settings.json
    const rawConfig: RawClaudeConfig = {
      ...emptyConfig("user"),
      settings: fileEntry("~/.claude/settings.json", "{ invalid json }", "user"),
    };

    // When the raw config is aggregated
    const aggregated = aggregateConfig(rawConfig);

    // Then envVars is empty (error path)
    expect(aggregated.envVars).toEqual([]);
  });
});

tests/unit/plugins/norbert-config/domain.source:
/**
 * Unit tests: settingsParser -- MCP server config and extractEnvVars
 *
 * Mutation-killing tests targeting:
 *   - createMcpServerConfig guard logic (lines 107-127)
 *   - extractEnvVars guard logic (lines 145-155)
 *   - Source field "settings.json" attribution
 */

import { describe, it, expect } from "vitest";
import {
  parseSettings,
  extractEnvVars,
} from "../../../../../src/plugins/norbert-config/domain/settingsParser";

// ---------------------------------------------------------------------------
// Helper: parse settings with mcpServers and return the MCP server list
// ---------------------------------------------------------------------------

function parseMcpServers(mcpServers: Record<string, unknown>) {
  const result = parseSettings(JSON.stringify({ mcpServers }));
  if (result.tag !== "parsed") throw new Error("Expected parsed result");
  return result.mcpServers;
}

// ---------------------------------------------------------------------------
// createMcpServerConfig: invalid config shapes
// ---------------------------------------------------------------------------

describe("createMcpServerConfig guard conditions", () => {
  it("server config that is an array produces invalid-config warning", () => {
    const servers = parseMcpServers({ "arr-srv": [1, 2, 3] });
    expect(servers).toHaveLength(1);
    expect(servers[0].warnings).toContain("Invalid server configuration");
    expect(servers[0].command).toBe("");
    expect(servers[0].type).toBe("");
    expect(servers[0].args).toEqual([]);
    expect(servers[0].env).toEqual([]);
    expect(servers[0].filePath).toBe("");
  });

  it("server config that is null produces invalid-config warning", () => {
    const servers = parseMcpServers({ "null-srv": null });
    expect(servers).toHaveLength(1);
    expect(servers[0].warnings).toContain("Invalid server configuration");
  });

  it("server config that is a string produces invalid-config warning", () => {
    const servers = parseMcpServers({ "str-srv": "just-a-string" });
    expect(servers).toHaveLength(1);
    expect(servers[0].warnings).toContain("Invalid server configuration");
  });

  it("server config that is a number produces invalid-config warning", () => {
    const servers = parseMcpServers({ "num-srv": 42 });
    expect(servers).toHaveLength(1);
    expect(servers[0].warnings).toContain("Invalid server configuration");
  });

  it("server config that is a boolean produces invalid-config warning", () => {
    const servers = parseMcpServers({ "bool-srv": true });
    expect(servers).toHaveLength(1);
    expect(servers[0].warnings).toContain("Invalid server configuration");
  });
});

// ---------------------------------------------------------------------------
// createMcpServerConfig: command field validation
// ---------------------------------------------------------------------------

describe("createMcpServerConfig command validation", () => {
  it("non-string command produces missing-command warning", () => {
    const servers = parseMcpServers({ "srv": { type: "stdio", command: 123 } });
    expect(servers).toHaveLength(1);
    expect(servers[0].warnings).toContain("Missing required field: command");
    expect(servers[0].command).toBe("");
  });

  it("null command produces missing-command warning", () => {
    const servers = parseMcpServers({ "srv": { type: "stdio", command: null } });
    expect(servers[0].warnings).toContain("Missing required field: command");
    expect(servers[0].command).toBe("");
  });

  it("empty string command produces missing-command warning", () => {
    const servers = parseMcpServers({ "srv": { type: "stdio", command: "" } });
    expect(servers[0].warnings).toContain("Missing required field: command");
    expect(servers[0].command).toBe("");
  });

  it("missing command field produces missing-command warning", () => {
    const servers = parseMcpServers({ "srv": { type: "stdio" } });
    expect(servers[0].warnings).toContain("Missing required field: command");
  });

  it("valid string command has no command warning", () => {
    const servers = parseMcpServers({
      "srv": { type: "stdio", command: "npx my-server" },
    });
    expect(servers[0].warnings).toEqual([]);
    expect(servers[0].command).toBe("npx my-server");
    expect(servers[0].filePath).toBe("");
  });
});

// ---------------------------------------------------------------------------
// createMcpServerConfig: type field extraction
// ---------------------------------------------------------------------------

describe("createMcpServerConfig type extraction", () => {
  it("non-string type defaults to empty string", () => {
    const servers = parseMcpServers({ "srv": { type: 42, command: "cmd" } });
    expect(servers[0].type).toBe("");
  });

  it("missing type defaults to empty string", () => {
    const servers = parseMcpServers({ "srv": { command: "cmd" } });
    expect(servers[0].type).toBe("");
  });

  it("valid string type is preserved", () => {
    const servers = parseMcpServers({ "srv": { type: "sse", command: "cmd" } });
    expect(servers[0].type).toBe("sse");
  });
});

// ---------------------------------------------------------------------------
// createMcpServerConfig: args field extraction
// ---------------------------------------------------------------------------

describe("createMcpServerConfig args extraction", () => {
  it("non-array args defaults to empty array", () => {
    const servers = parseMcpServers({
      "srv": { type: "stdio", command: "cmd", args: "not-array" },
    });
    expect(servers[0].args).toEqual([]);
  });

  it("null args defaults to empty array", () => {
    const servers = parseMcpServers({
      "srv": { type: "stdio", command: "cmd", args: null },
    });
    expect(servers[0].args).toEqual([]);
  });

  it("args containing non-strings are filtered out", () => {
    const servers = parseMcpServers({
      "srv": {
        type: "stdio",
        command: "cmd",
        args: ["valid", 42, null, "also-valid", true, undefined],
      },
    });
    expect(servers[0].args).toEqual(["valid", "also-valid"]);
  });

  it("args with only strings preserves all", () => {
    const servers = parseMcpServers({
      "srv": { type: "stdio", command: "cmd", args: ["--flag", "value"] },
    });
    expect(servers[0].args).toEqual(["--flag", "value"]);
  });

  it("missing args field defaults to empty array", () => {
    const servers = parseMcpServers({ "srv": { type: "stdio", command: "cmd" } });
    expect(servers[0].args).toEqual([]);
  });
});

// ---------------------------------------------------------------------------
// createMcpServerConfig: source attribution
// ---------------------------------------------------------------------------

describe("createMcpServerConfig source attribution", () => {
  it("source is always 'settings.json'", () => {
    const servers = parseMcpServers({
      "srv": { type: "stdio", command: "cmd", args: [] },
    });
    expect(servers[0].source).toBe("settings.json");
  });

  it("invalid config also has source 'settings.json'", () => {
    const servers = parseMcpServers({ "srv": null });
    expect(servers[0].source).toBe("settings.json");
  });

  it("scope from parseSettings propagates to server config", () => {
    const result = parseSettings(
      JSON.stringify({ mcpServers: { "srv": { type: "stdio", command: "cmd" } } }),
      "project",
    );
    if (result.tag !== "parsed") throw new Error("Expected parsed result");
    expect(result.mcpServers[0].scope).toBe("project");
  });
});

// ---------------------------------------------------------------------------
// extractEnvVars: guard conditions
// ---------------------------------------------------------------------------

describe("extractEnvVars guard conditions", () => {
  it("null input returns empty array", () => {
    expect(extractEnvVars(null)).toEqual([]);
  });

  it("undefined input returns empty array", () => {
    expect(extractEnvVars(undefined)).toEqual([]);
  });

  it("array input returns empty array", () => {
    expect(extractEnvVars(["key", "value"])).toEqual([]);
  });

  it("string input returns empty array", () => {
    expect(extractEnvVars("not-an-object")).toEqual([]);
  });

  it("number input returns empty array", () => {
    expect(extractEnvVars(42)).toEqual([]);
  });

  it("boolean input returns empty array", () => {
    expect(extractEnvVars(true)).toEqual([]);
  });

  it("valid object extracts string key-value pairs", () => {
    const result = extractEnvVars({ API_KEY: "secret", PORT: "3000" });
    expect(result).toEqual([
      { key: "API_KEY", value: "secret" },
      { key: "PORT", value: "3000" },
    ]);
  });

  it("filters out non-string values from env object", () => {
    const result = extractEnvVars({
      GOOD: "yes",
      BAD_NUM: 42,
      BAD_NULL: null,
      ALSO_GOOD: "ok",
      BAD_BOOL: true,
    });
    expect(result).toEqual([
      { key: "GOOD", value: "yes" },
      { key: "ALSO_GOOD", value: "ok" },
    ]);
  });

  it("empty object returns empty array", () => {
    expect(extractEnvVars({})).toEqual([]);
  });
});

tests/acceptance/norbert-config/config-a.source:
/**
 * Acceptance tests: Configuration Aggregation (US-001, US-005, US-006, US-007)
 *
 * Validates that raw config data from .claude/ directories is aggregated
 * into a unified, scope-annotated structure ready for all 7 tabs.
 * Covers full directory parsing, partial directories, per-file error
 * isolation, and dual-scope merging.
 *
 * Driving ports: pure domain function (aggregateConfig)
 * These tests exercise the data aggregation that feeds the Configuration
 * Viewer, not the React rendering or Rust filesystem reader.
 *
 * Traces to: US-001, US-005, US-006, US-007 acceptance criteria
 */

import { describe, it, expect } from "vitest";
import {
  aggregateConfig,
  type RawClaudeConfig,
  type AggregatedConfig,
  type FileEntry,
  type ReadErrorInfo,
} from "../../../src/plugins/norbert-config/domain/configAggregator";

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

const fileEntry = (path: string, content: string, scope: "user" | "project"): FileEntry => ({
  path,
  content,
  scope,
});

const readError = (path: string, error: string, scope: "user" | "project"): ReadErrorInfo => ({
  path,
  error,
  scope,
});

const emptyConfig = (scope: "user" | "project" | "both"): RawClaudeConfig => ({
  agents: [],
  commands: [],
  skills: [],
  settings: null,
  claudeMdFiles: [],
  errors: [],
  scope,
});

// ---------------------------------------------------------------------------
// WALKING SKELETON
// ---------------------------------------------------------------------------

// @walking_skeleton
describe("User sees all configuration categories from .claude/ directory", () => {
  it("aggregates agents, hooks, skills, rules, MCP servers, and docs into unified view", () => {
    // Given a .claude/ directory with agents, commands, settings, and CLAUDE.md
    const rawConfig: RawClaudeConfig = {
      agents: [
        fileEntry(
          "~/.claude/agents/software-crafter.md",
          "---\nmodel: opus-4\ntools:\n  - Bash\n  - Read\n---\n\nYou are a software crafter.",
          "user",
        ),
        fileEntry(
          "~/.claude/agents/reviewer.md",
          "---\nmodel: sonnet-4\n---\n\nReview code for quality.",
          "user",
        ),
      ],
      commands: [
        fileEntry(
          "~/.claude/commands/deploy.md",
          "# Deploy to staging\n\nDeploy the current branch.",
          "user",
        ),
      ],
      skills: [],
      settings: fileEntry(
        "~/.claude/settings.json",
        JSON.stringify({
          hooks: {
            PreToolUse: [{ command: "/usr/local/bin/norbert-hook", matchers: ["Bash"] }],
          },
          mcpServers: {
            "fs-server": { type: "stdio", command: "npx", args: ["@anthropic/mcp-filesystem"] },
          },
          rules: ["Use TypeScript strict mode"],
        }),
        "user",
      ),
      claudeMdFiles: [
        fileEntry("./CLAUDE.md", "# Norbert\n\nLocal-first observability app.", "project"),
      ],
      errors: [],
      scope: "both",
    };

    // When the raw config is aggregated
    const aggregated = aggregateConfig(rawConfig);

    // Then 2 agent definitions are available
    expect(aggregated.agents).toHaveLength(2);

    // And 1 command definition is available
    expect(aggregated.commands).toHaveLength(1);

    // And 1 hook binding is available
    expect(aggregated.hooks).toHaveLength(1);

    // And 1 MCP server is available
    expect(aggregated.mcpServers).toHaveLength(1);

    // And 1 rule is available
    expect(aggregated.rules).toHaveLength(1);

    // And 1 doc file is available
    expect(aggregated.docs).toHaveLength(1);

    // And no errors occurred
    expect(aggregated.errors).toHaveLength(0);
  });
});

// ---------------------------------------------------------------------------
// FOCUSED SCENARIOS
// ---------------------------------------------------------------------------

describe("Missing subdirectories produce empty lists, not errors", () => {
  it("returns empty agents and skills when no agent or command files exist", () => {
    // Given a .claude/ directory with only settings.json (no agents/ or commands/)
    const rawConfig: RawClaudeConfig = {
      ...emptyConfig("user"),
      settings: fileEntry(
        "~/.claude/settings.json",
        JSON.stringify({ hooks: {}, mcpServers: {} }),
        "user",
      ),
    };

    // When the raw config is aggregated
    const aggregated = aggregateConfig(rawConfig);

    // Then agents list is empty
    expect(aggregated.agents).toEqual([]);

    // And skills list is empty
    expect(aggregated.skills).toEqual([]);

    // And no errors are reported
    expect(aggregated.errors).toEqual([]);
  });
});

describe("Both user and project scopes aggregated with source annotations", () => {
  it("combines agents from user and project scopes with scope annotation", () => {
    // Given agents exist in both user (~/.claude/) and project (./.claude/) scopes
    const rawConfig: RawClaudeConfig = {
      agents: [
        fileEntry(
          "~/.claude/agents/global-crafter.md",
          "---\nmodel: opus-4\n---\n\nGlobal crafter agent.",
          "user",
        ),
        fileEntry(
          "./.claude/agents/project-helper.md",
          "---\nmodel: sonnet-4\n---\n\nProject-specific helper.",
          "project",
        ),
      ],
      commands: [],
      skills: [],
      settings: null,
      claudeMdFiles: [],
      errors: [],
      scope: "both",
    };

    // When the raw config is aggregated
    const aggregated = aggregateConfig(rawConfig);

    // Then both agents are present
    expect(aggregated.agents).toHaveLength(2);

    // And each carries its source scope
    const userAgent = aggregated.agents.find(
      (a) => a.tag === "parsed" && a.agent.scope === "user",
    );
    const projectAgent = aggregated.agents.find(
      (a) => a.tag === "parsed" && a.agent.scope === "project",
    );
    expect(userAgent).toBeDefined();
    expect(projectAgent).toBeDefined();
  });
});

describe("Doc files passed through with scope and path", () => {
  it("includes CLAUDE.md files with their source paths and scopes", () => {
    // Given CLAUDE.md files at project root and in .claude/
    const rawConfig: RawClaudeConfig = {
      ...emptyConfig("both"),
      claudeMdFiles: [
        fileEntry("./CLAUDE.md", "# Norbert\n\nProject instructions.", "project"),
        fileEntry("~/.claude/CLAUDE.md", "# Memory Index\n\nUser memory.", "user"),
      ],
    };

    // When the raw config is aggregated
    const aggregated = aggregateConfig(rawConfig);

    // Then 2 doc files are available
    expect(aggregated.docs).toHaveLength(2);

    // And each carries its file path and scope
    expect(aggregated.docs[0].filePath).toBe("./CLAUDE.md");
    expect(aggregated.docs[0].scope).toBe("project");
    expect(aggregated.docs[1].filePath).toBe("~/.claude/CLAUDE.md");
    expect(aggregated.docs[1].scope).toBe("user");
  });
});

describe("Agents from both scopes combined in aggregated result", () => {
  it("merges user-level and project-level agent lists", () => {
    // Given 2 user agents and 1 project agent
    const rawConfig: RawClaudeConfig = {
      agents: [
        fileEntry("~/.claude/agents/a.md", "---\nmodel: opus-4\n---\n\nAgent A.", "user"),
        fileEntry("~/.claude/agents/b.md", "---\nmodel: opus-4\n---\n\nAgent B.", "user"),
        fileEntry("./.claude/agents/c.md", "---\nmodel: sonnet-4\n---\n\nAgent C.", "project"),
      ],
      commands: [],
      skills: [],
      settings: null,
      claudeMdFiles: [],
      errors: [],
      scope: "both",
    };

    // When the raw config is aggregated
    const aggregated = aggregateConfig(rawConfig);

    // Then all 3 agents are in the result
    expect(aggregated.agents).toHaveLength(3);
  });
});

// ---------------------------------------------------------------------------
// ERROR / BOUNDARY SCENARIOS
// ---------------------------------------------------------------------------

describe("Per-file read errors isolated from successful reads", () => {
  it("returns successful agents alongside errors for unreadable files", () => {
    // Given 3 agent files where 1 produced a read error
    const rawConfig: RawClaudeConfig = {
      agents: [
        fileEntry("~/.claude/agents/good-1.md", "---\nmodel: opus-4\n---\n\nGood agent.", "user"),
        fileEntry("~/.claude/agents/good-2.md", "---\nmodel: sonnet-4\n---\n\nAnother good agent.", "user"),
      ],
      commands: [],
      skills: [],
      settings: null,
      claudeMdFiles: [],
      errors: [
        readError("~/.claude/agents/broken.md", "Permission denied", "user"),
      ],
      scope: "user",
    };

    // When the raw config is aggregated
    const aggregated = aggregateConfig(rawConfig);

    // Then 2 agents are successfully parsed
    expect(aggregated.agents).toHaveLength(2);

    // And 1 error is reported for the unreadable file
    expect(aggregated.errors).toHaveLength(1);
    expect(aggregated.errors[0].path).toContain("broken.md");
    expect(aggregated.errors[0].error).toBe("Permission denied");
  });
});

describe("Settings parse error does not break agent and skill lists", () => {
  it("returns agents and skills even when settings.json is malformed", () => {
    // Given agents and commands are readable but settings.json is malformed
    const rawConfig: RawClaudeConfig = {
      agents: [
        fileEntry("~/.claude/agents/crafter.md", "---\nmodel: opus-4\n---\n\nA crafter.", "user"),
      ],
      commands: [
        fileEntry("~/.claude/commands/deploy.md", "# Deploy\n\nDeploy to staging.", "user"),
      ],
      skills: [],
      settings: fileEntry(
        "~/.claude/settings.json",
        "{ invalid json }",
        "user",
      ),
      claudeMdFiles: [],
      errors: [],
      scope: "user",
    };

    // When the raw config is aggregated
    const aggregated = aggregateConfig(rawConfig);

    // Then agents are still parsed
    expect(aggregated.agents).toHaveLength(1);

    // And commands are still parsed
    expect(aggregated.commands).toHaveLength(1);

    // And hooks/mcpServers/rules are empty due to the parse error
    expect(aggregated.hooks).toEqual([]);
    expect(aggregated.mcpServers).toEqual([]);
    expect(aggregated.rules).toEqual([]);
  });
});

describe("Completely empty config produces all-empty aggregated result", () => {
  it("returns empty lists for all categories when .claude/ has no files", () => {
    // Given no files exist in .claude/ at all
    const rawConfig: RawClaudeConfig = emptyConfig("both");

    // When the raw config is aggregated
    const aggregated = aggregateConfig(rawConfig);

    // Then all categories are empty
    expect(aggregated.agents).toEqual([]);
    expect(aggregated.skills).toEqual([]);
    expect(aggregated.hooks).toEqual([]);
    expect(aggregated.mcpServers).toEqual([]);
    expect(aggregated.rules).toEqual([]);
    expect(aggregated.plugins).toEqual([]);
    expect(aggregated.docs).toEqual([]);
    expect(aggregated.errors).toEqual([]);
  });
});

describe("Read errors carry scope annotation", () => {
  it("preserves the scope on error entries for source attribution", () => {
    // Given a read error from the project scope
    const rawConfig: RawClaudeConfig = {
      ...emptyConfig("both"),
      errors: [
        readError("./.claude/agents/broken.md", "File not found", "project"),
      ],
    };

    // When the raw config is aggregated
    const aggregated = aggregateConfig(rawConfig);

    // Then the error carries the project scope
    expect(aggregated.errors).toHaveLength(1);
    expect(aggregated.errors[0].scope).toBe("project");
  });
});

